#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Scale the QA auditor 1 -> 10 instances (exit-0-safe). It's a template service designed
for instances (claims via SKIP LOCKED like the enrich pool). QA is the prospect gate;
more graders = more qualified prospects surfaced. Measures QA grading rate after."""
import os,sys,json,time,subprocess
def sh(c,t=40):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else "ERR")
out={"kind":"scaleqa","ts":int(time.time())}
try:
    out["qa_before"]=sh("systemctl list-units 'atlas-qa-auditor@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
    insts=" ".join("atlas-qa-auditor@%d.service"%i for i in range(1,11))
    out["enable"]=sh("systemctl enable --now %s 2>&1 | tail -2"%insts, t=60)
    out["qa_after_units"]=sh("systemctl list-units 'atlas-qa-auditor@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
    # measure QA grading rate: qa_status-set delta over 45s
    c0=psql("SELECT count(*) FILTER (WHERE qa_status IS NOT NULL AND qa_status<>'') FROM atlas.business"); t0=time.time()
    time.sleep(45)
    c1=psql("SELECT count(*) FILTER (WHERE qa_status IS NOT NULL AND qa_status<>'') FROM atlas.business"); t1=time.time()
    out["qa_checked_t0"]=c0; out["qa_checked_t1"]=c1
    try: out["QA_per_min"]=round((int(c1)-int(c0))*60.0/(t1-t0),1)
    except Exception: pass
    out["pass_now"]=psql("SELECT count(*) FILTER (WHERE qa_status='pass') FROM atlas.business")
    out["active"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["total"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
    out["waiting_lock"]=psql("SELECT count(*) FROM pg_stat_activity WHERE wait_event_type='Lock'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/scaleqa.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"scaleqa","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
